button2.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View view) {

                AlertDialog.Builder dialog = new  AlertDialog.Builder(MainActivity.this);
                dialog.setTitle("肖书尧的自定义对话框");
                dialog.setIcon(R.drawable.kulou);
                dialog.setMessage("请输入用户名密码");
                linearLayout=(LinearLayout)getLayoutInflater().inflate(R.layout.layout_xsy2,null);
                dialog.setView(linearLayout);
                dialog.setPositiveButton("确定", new DialogInterface.OnClickListener() {

                    EditText nm =null,pw =null;
                    @Override
                    public void onClick(DialogInterface dialogInterface, int i) {
                        nm = (EditText)linearLayout.findViewById(R.id.editTextTextPassword);
                        pw =(EditText)linearLayout.findViewById(R.id.editTextTextPersonName3);
                        if(pw.getText().toString().equals("xsy")&&nm.getText().toString().equals("8888"))
                        {
                            Toast.makeText(getApplicationContext(),"登录成功",Toast.LENGTH_SHORT).show();
                        }else{
                            Toast.makeText(getApplicationContext(),"登录失败",Toast.LENGTH_SHORT).show();
                        }
//                            setContentView(R.layout.linearlayout_xsy2);

                    }
                });
                dialog.setNegativeButton("取消",new DialogInterface.OnClickListener() {
                    @Override
                    public void onClick(DialogInterface dialogInterface, int i) {
                        Toast.makeText(getApplicationContext(),"取消登录",Toast.LENGTH_SHORT).show();
                    }
                });
                dialog.create();
                dialog.show();

            }

        });解释上面代码的作用

